noncompliant:
resource customOwnerRole 'Microsoft.Authorization/roleDefinitions@2022-04-01' = {
  name: guid('custom-owner-role')
  properties: {
    roleName: 'Custom Owner Role'
    description: 'Grants all permissions including Owner capabilities'
    type: 'CustomRole'
    permissions: [
      {
        actions: ['*'] // Sensitive: wildcard permission
        notActions: []
      }
    ]
    assignableScopes: [
      '/subscriptions/xxxx'
    ]
  }
}

compliant:
resource customReaderRole 'Microsoft.Authorization/roleDefinitions@2022-04-01' = {
  name: guid('custom-reader-role')
  properties: {
    roleName: 'Custom Reader Role'
    description: 'Grants only read permissions'
    type: 'CustomRole'
    permissions: [
      {
        actions: [
          'Microsoft.Resources/subscriptions/resourceGroups/read'
        ]
        notActions: []
      }
    ]
    assignableScopes: [
      '/subscriptions/xxxx'
    ]
  }
}
